#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <arpa/inet.h>
#include <pthread.h>

#define PORT 9000
#define BUFFER_SIZE 1024
#define MAX_CLIENTS 5

// Process client request
char* process_request(const char* request) {
 char* response = malloc(BUFFER_SIZE);

 if (strncmp(request, "READ:", 5) == 0) {
 const char* filename = request + 5;
 snprintf(response, BUFFER_SIZE, "Contents of %s: [data]", filename);
 } 
 else if (strncmp(request, "WRITE:", 6) == 0) {
 const char* data = request + 6;
 snprintf(response, BUFFER_SIZE, "Successfully wrote: %s", data);
 } 
 else if (strncmp(request, "COMPUTE:", 8) == 0) {
 const char* task = request + 8;
 snprintf(response, BUFFER_SIZE, "Computed %s: DONE", task);
 } 
 else {
 strcpy(response, "ERROR: Unknown request");
 }

 return response;
}

// Handle individual client in separate thread
void* handle_client(void* arg) {
 int client_socket = *(int*)arg;
 free(arg);

 char buffer[BUFFER_SIZE] = {0};

 // Receive data from client
 ssize_t bytes_read = read(client_socket, buffer, BUFFER_SIZE);
 if (bytes_read > 0) {
 printf("[>] Received: %s\n", buffer);

 // Process request
 char* response = process_request(buffer);

 // Send response
 send(client_socket, response, strlen(response), 0);
 printf("[<] Sent: %s\n", response);

 free(response);
 }

 close(client_socket);
 return NULL;
}

// Server initialization and listening
void start_server() {
 int server_socket, client_socket;
 struct sockaddr_in address;
 int opt = 1;
 socklen_t addrlen = sizeof(address);

 // Create socket
 server_socket = socket(AF_INET, SOCK_STREAM, 0);
 if (server_socket < 0) {
 perror("Socket creation failed");
 exit(EXIT_FAILURE);
 }

 // Set socket options
 if (setsockopt(server_socket, SOL_SOCKET, SO_REUSEADDR, &opt, sizeof(opt))) {
 perror("setsockopt failed");
 exit(EXIT_FAILURE);
 }

 // Configure address
 address.sin_family = AF_INET;
 address.sin_addr.s_addr = INADDR_ANY;
 address.sin_port = htons(PORT);

 // Bind socket
 if (bind(server_socket, (struct sockaddr*)&address, sizeof(address)) < 0) {
 perror("Bind failed");
 exit(EXIT_FAILURE);
 }

 // Listen for connections
 if (listen(server_socket, MAX_CLIENTS) < 0) {
 perror("Listen failed");
 exit(EXIT_FAILURE);
 }

 printf("[*] Server listening on port %d\n", PORT);

 // Accept client connections
 while (1) {
 client_socket = accept(server_socket, (struct sockaddr*)&address, &addrlen);
 if (client_socket < 0) {
 perror("Accept failed");
 continue;
 }

 printf("[+] New connection accepted\n");

 // Create thread to handle client
 pthread_t thread_id;
 int* client_sock = malloc(sizeof(int));
 *client_sock = client_socket;

 if (pthread_create(&thread_id, NULL, handle_client, client_sock) < 0) {
 perror("Thread creation failed");
 close(client_socket);
 }

 pthread_detach(thread_id);
 }
}

// Client function
void client_request(const char* message) {
 int sock = 0;
 struct sockaddr_in serv_addr;
 char buffer[BUFFER_SIZE] = {0};

 // Create socket
 sock = socket(AF_INET, SOCK_STREAM, 0);
 if (sock < 0) {
 printf("[-] Socket creation error\n");
 return;
 }

 serv_addr.sin_family = AF_INET;
 serv_addr.sin_port = htons(PORT);

 // Convert address
 if (inet_pton(AF_INET, "127.0.0.1", &serv_addr.sin_addr) <= 0) {
 printf("[-] Invalid address\n");
 return;
 }

 // Connect to server
 if (connect(sock, (struct sockaddr*)&serv_addr, sizeof(serv_addr)) < 0) {
 printf("[-] Connection failed\n");
 return;
 }

 // Send message
 send(sock, message, strlen(message), 0);
 printf("[>] Sent: %s\n", message);

 // Receive response
 read(sock, buffer, BUFFER_SIZE);
 printf("[<] Received: %s\n", buffer);

 close(sock);
}

int main(int argc, char* argv[]) {
 if (argc > 1 && strcmp(argv[1], "server") == 0) {
 start_server();
 } else {
 printf("=== C Client Demo ===\n");
 printf("1. READ request:\n");
 client_request("READ:data.txt");

 printf("\n2. WRITE request:\n");
 client_request("WRITE:test.txt|Hello World");

 printf("\n3. COMPUTE request:\n");
 client_request("COMPUTE:sort");
 }

 return 0;
}
